import React from "react";

const CommonTable = ({  data = [], columns = [], renderActions, noRecordMessage = "No Record Found", tableId = "common-table", }) => 
  {
  return (
    <div className="table-responsive">
      {data.length === 0 ? (
        <h4 className="text-muted p-5 text-center fw-bold">
          {noRecordMessage}
        </h4>
      ) : (
        <table id={tableId} className="table table-striped form-label col-form-label col-form-label-sm" role="grid" >
          <thead>
            <tr className="align-top"> {columns.map((col, index) => ( 
              <th key={index} style={col.style} className="align-top"> {col.header} </th>
               ))}
              {renderActions && (
                <th style={{ minWidth: "100px" }} className="align-top">Action</th>
              )}
            </tr>
          </thead>
<thead>
  <tr className="align-top">
    {columns.map((col, index) => (
      <th
        key={index}
        style={col.style}
        className="align-top"
      >
        {col.header}
      </th>
    ))}

    {renderActions && (
      <th
        style={{ minWidth: "100px" }}
        className="align-top"
      >
        Action
      </th>
    )}
  </tr>
</thead>
          <tbody>
            {data.map((row, rowIndex) => (
              <tr key={row.id || row.office_id || rowIndex} className="align-top">
                {columns.map((col, colIndex) => (
                  <td key={colIndex} className="align-top">
                    {col.render
                      ? col.render(row, rowIndex)
                      : row[col.accessor]}
                  </td>
                ))}

                {renderActions && (
                  <td className="align-top">
                    <div className="d-flex align-items-center gap-2">
                      {renderActions(row)}
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default CommonTable;
